/**
 * Tuple of an RGB color value and an intensity value.
 *
 * @since 5.0
 */
export interface ColorAndIntensity {
  /**
   * RGB color with values between 0 and 1.
   *
   * @since 5.0
   */
  color: [
      number,
      number,
      number
  ];
  /**
   * Scalar intensity value by which the color should be scaled for compositing.
   *
   * @since 5.0
   */
  intensity: number;
}

/**
 * Describes the lighting used by [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/), derived from its sun
 * lighting model. It consists of a directional
 * Lambertian (`diffuse`) and a constant (`ambient`) term, which should be treated in the sense of the
 * [Phong Reflection Model](https://en.wikipedia.org/wiki/Phong_reflection_model).
 *
 * @since 5.0
 */
export interface SunLight {
  /**
   * The incident light direction in render coordinates.
   *
   * @since 5.0
   */
  direction: [
      number,
      number,
      number
  ];
  /**
   * The ambient light color and intensity.
   *
   * @since 5.0
   */
  ambient: ColorAndIntensity;
  /**
   * The diffuse light color and intensity.
   *
   * @since 5.0
   */
  diffuse: ColorAndIntensity;
}